#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 10005
#define INF 0x3f3f3f3f

int max(int a, int b) { return a > b ? a : b; }

int dp[MAXN][MAXN];
int a[MAXN], b[MAXN];

int dfs(int i, int j) {
    if (i == -1) return 0;
    if (dp[i][j] != -1) return dp[i][j];
    int res = -INF;
    for (int k = max(0, j - 1); k <= min(j + 1, i); k++) {
        res = max(res, dfs(i - 1, k) + b[i] + a[k]);
    }
    return dp[i][j] = res;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        for (int i = 0; i < n; i++) scanf("%d", &b[i]);
        for (int i = 0; i < n; i++) scanf("%d", &a[i]);
        memset(dp, -1, sizeof(dp));
        int ans = dfs(n - 1, 0);
        printf("%d\n", ans);
    }
    return 0;
}

